/**
 * Tests for prompt/prompt-expansion-observer (UserPromptExpansion, CC 2.1.208).
 *
 * P3-A3 contract: OBSERVER ONLY. Every input — empty, malformed, oversized —
 * must return { continue: true, suppressOutput: true } with no block, no
 * message, no modification. Telemetry lines never carry raw prompt content.
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return { ...actual, logHook: vi.fn() };
});

import { promptExpansionObserver } from '../../prompt/prompt-expansion-observer.js';
import { logHook } from '../../lib/common.js';

function expectSilentContinue(result: Record<string, unknown>): void {
  expect(result.continue).toBe(true);
  expect(result.suppressOutput).toBe(true);
  expect(result.decision).toBeUndefined();
  expect(result.systemMessage).toBeUndefined();
  expect(result.hookSpecificOutput).toBeUndefined();
}

describe('prompt/prompt-expansion-observer', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test('empty input {} returns silent continue', async () => {
    const result = await promptExpansionObserver({} as HookInput);
    expectSilentContinue(result as unknown as Record<string, unknown>);
  });

  test('absent/unknown fields return silent continue', async () => {
    const input = {
      hook_event: 'UserPromptExpansion',
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
      some_future_field: { nested: true },
      prompt: 42, // wrong type — must be tolerated
    } as unknown as HookInput;
    const result = await promptExpansionObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);
  });

  test('oversized payload returns silent continue and caps the logged line', async () => {
    const huge = `/deploy ${'x'.repeat(2 * 1024 * 1024)}`;
    const input = {
      hook_event: 'UserPromptExpansion',
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
      prompt: huge,
      expanded_prompt: 'y'.repeat(1024 * 1024),
    } as unknown as HookInput;

    const result = await promptExpansionObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);

    // Telemetry must be compact metrics — never the raw payload
    const line = vi.mocked(logHook).mock.calls[0]?.[1] ?? '';
    expect(line.length).toBeLessThan(256);
    expect(line).not.toContain('xxxxxxxxxx');
    expect(line).toContain('cmd=/deploy');
  });

  test('never logs raw prompt content, only sanitized command token', async () => {
    const input = {
      prompt: '/commit -m "secret token ghp_abc123"; rm -rf /',
      session_id: 'test-session',
      tool_name: '',
      tool_input: {},
    } as unknown as HookInput;
    const result = await promptExpansionObserver(input);
    expectSilentContinue(result as unknown as Record<string, unknown>);

    const line = vi.mocked(logHook).mock.calls[0]?.[1] ?? '';
    expect(line).not.toContain('ghp_abc123');
    expect(line).not.toContain('rm -rf');
    expect(line).toContain('cmd=/commit');
  });
});
